/* Generated from .env - MySQL version */
AS new_values (setting_key, setting_value, description, config_type, updated_at_utc, updated_by)
ON DUPLICATE KEY UPDATE
    setting_value  = new_values.setting_value,
    description    = new_values.description,
    config_type    = new_values.config_type,
    updated_at_utc = new_values.updated_at_utc,
    updated_by     = new_values.updated_by;

SELECT ROW_COUNT() AS rows_affected;